using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using System.Collections;
public class Script {
    public static object Main() {
        var controllers = Object.FindObjectsOfType<AnimalController>();
        var sb = new System.Text.StringBuilder();
        foreach (var c in controllers) {
            var sd = c.StateData;
            if (sd == null || sd.AnimalType != 2) continue;
            sb.AppendLine($"Bird Entity={sd.EntityId} State={sd.AnimalState} Speed={sd.MoveSpeed:F2} Y={c.transform.position.y:F1} Pos=({c.transform.position.x:F1},{c.transform.position.z:F1})");
        }
        return sb.Length > 0 ? sb.ToString() : "No birds";
    }
}
